body.script:
// DataLayer para los page view
window.dataLayer = window.dataLayer || [];
window.dataLayer.push({
    'event': 'page_view',
    'page_type': '',
    'page_content': '',
    'page_language': 'es',
});

// DataLayer para los formularios
document.addEventListener("DOMContentLoaded", () => {
    // Función para calcular el hash SHA-256
    async function sha256(text) {
        // Convierte el texto a un Uint8Array
        var encoder = new TextEncoder();
        var data = encoder.encode(text);

        // Calcula el hash
        var hashBuffer = await crypto.subtle.digest('SHA-256', data);

        // Convierte el resultado en una cadena hexadecimal
        return Array.from(new Uint8Array(hashBuffer))
            .map((byte) => byte.toString(16).padStart(2, '0'))
            .join('');
    }
    // Formulario de búsqueda
    var searchForm = document.querySelector(
        '.content-form-search-blog, .content-form-filter-faqs, .content-form-filter-entidades'
    );
    if (searchForm) {
        searchForm.addEventListener('submit', (event) => {
            event.preventDefault();

            var searchInput = searchForm.querySelector('input[name="search"]') || searchForm.querySelector('input[name="s"]');
            var query = searchInput ? searchInput.value : '';


            if (query.length > 0) {
                window.dataLayer.push({
                    'event': 'search',
                    'search_term': query
                });
            }

            var url = new URL(window.location.href);
            var isBlog = searchForm.classList.contains('content-form-search-blog');
            var paramName = isBlog ? 's' : 'search';
            url.searchParams.set(paramName, query);

            if (isBlog) {
                // Si es el formulario del blog, hacemos un refresh de la página
                window.location.href = url.toString();
            } else {
                // Para los otros formularios, mantenemos el comportamiento actual
                window.history.replaceState({}, '', url);
            }
        });
    }

    // Formulario de contacto
    var contactForm = document.querySelector('.wpcf7-form');
    if (contactForm && contactForm.querySelector('#contact')) {
        contactForm.addEventListener('submit', async (event) => {
            event.preventDefault();

            var formDataContact = new FormData(contactForm);

            var isValid = true;


            var selectElement = document.getElementById('asunto');
            var optionsArray = Array.from(selectElement.options);
            var selectedIndex = optionsArray.findIndex(function(option) {
                return option.selected;
            });

            const optionsArrayEsp = [
                "",
                "Activación",
                "Consulta",
                "Incidencia",
                "Estafa",
                "Ejercicio de derechos",
                "Otro"
            ];


            if (contactForm.querySelectorAll('[aria-invalid="true"]').length > 0 || formDataContact.get('elige_entidad') === null) {
                isValid = false;
            }

            if (isValid) {
                dataLayer.push({
                    'event': 'generate_lead',
                    'lead_type': 'formulario-contacto_' + formDataContact.get('queEres').toLowerCase(),
                    'lead_email': await sha256(formDataContact.get('userEmail')),
                    'lead_id': 'XXXXXXXXX',
                    'asunto': optionsArrayEsp[selectedIndex],
                });
            } else {
                var errors = [];
                (contactForm.querySelectorAll('[aria-invalid="true"]')).forEach(value => {
                    if (value.name !== 'file-1') {
                        errors.push(value.name)
                    }
                });

                if (formDataContact.get('elige_entidad') === null) {
                    errors.push('eligeEntidad');
                }

                dataLayer.push({
                    'event': 'form_error',
                    'lead_type': 'formulario-contacto_' + formDataContact.get('queEres').toLowerCase(),
                    'error': errors.join('|')
                })
            }
        });
    }

    // Formulario de newsletter
    var newsletterForm = document.querySelector('#signup-newsletter form');
    if (newsletterForm) {
        newsletterForm.addEventListener('submit', async (event) => {
            event.preventDefault();

            var newsletterEmail = newsletterForm.querySelector('input[name="email"]');
            var newsletterEmailValue = newsletterEmail ? newsletterEmail.value : '';

            dataLayer.push({
                'event': 'generate_lead',
                'lead_type': 'formulario-newsletter',
                'lead_email': await sha256(newsletterEmailValue),
                'lead_id': 'XXXXXXXXX',
                'asunto': 'Newsletter',
            });
        });
    }


    var elementos = document.querySelectorAll('[data-event]');

    // Itera sobre cada elemento y le asigna un listener
    elementos.forEach(function(el) {
        el.addEventListener('click', function(event) {
            var content_type = null;
            var content_interaction = null;

            var evento = el.getAttribute('data-event');
            console.log('Se hizo click en un elemento con data-event:', evento);

            if (evento) {
                content_type = evento;

                if (el.closest('.site-header')) {
                    content_interaction = 'header';
                } else if (['cta_activar-bizum', 'cta_integrar-bizum'].includes(evento)) {
                    content_interaction = 'body';
                }

                if (evento === 'text_mas-informacion') {
                    content_interaction = el.getAttribute('href');
                }

                if (evento.startsWith('tab_como-funciona')) {
                    content_type = 'tab_como-funciona';
                    var contenidos = {
                        'tab_como-funciona-0': 'Enviar y recibir dinero',
                        'tab_como-funciona-1': 'Comprar online',
                        'tab_como-funciona-2': 'Identificación online',
                        'tab_como-funciona-3': 'Donar a causas sociales',
                        'tab_como-funciona-4': 'Pago presencial',
                        'tab_como-funciona-5': 'Pago y cobro de loterías'
                    }
                    content_interaction = contenidos[evento];
                }

                if (content_type !== null) {
                    dataLayer.push({
                        'event': 'select_content',
                        content_type,
                        content_interaction
                    });
                }
            }
        });
    });
});

// DataLayer para los CTA
document.addEventListener("click", (event) => {
    var clickedElement = event.target.closest('a');
    var content_type = null;
    var content_interaction = null;


    // Header principal
    if (clickedElement && clickedElement.closest('#main-menu')) {
        // Determinar el tipo de menú basado en el ancho de la ventana
        content_type = window.innerWidth >= 1121 ? 'menu_header' : 'menu_mobile';
        content_interaction = clickedElement.textContent.trim();
    }

    // Header CTA Idiomas
    if (clickedElement && clickedElement.closest('#language-selector')) {
        content_type = 'menu_header';
        content_interaction = clickedElement.textContent.trim();
    }

    // Footer principal
    if (clickedElement && clickedElement.closest('.footer-site-menu')) {
        content_type = 'menu_footer';
        content_interaction = clickedElement.textContent.trim();
    }

    // CTA Accesibilidad
    if (clickedElement && clickedElement.closest('.content-panel-accessibility__font-size')) {
        content_type = 'cta_accesibilidad';
        content_interaction = clickedElement.textContent.trim();
    }

    // Checkbox de accesibilidad
    if (clickedElement === null && event.target.type === 'checkbox' && (event.target.closest('#toggle-gray-scale') || event.target.closest('#toggle-dark-mode'))) {
        content_type = 'cta_accesibilidad';

        if (event.target.closest('#toggle-gray-scale')) {
            if (event.target.classList.contains('is-checked')) {
                content_interaction = 'off';
            } else {
                content_interaction = 'on';
            }
        } else {
            if (event.target.classList.contains('is-checked')) {
                content_interaction = 'light';
            } else {
                content_interaction = 'dark';
            }
        }
    }

    // CTA de botones
    if (clickedElement && clickedElement.classList.contains('wp-button-link')) {
        if (clickedElement.href.includes('/blog/')) {
            content_type = 'cta_seguir-leyendo';
            content_interaction = clickedElement.href;
        }
    }

    if (clickedElement && event.target.type === 'submit' && event.target.closest('#signup-newsletter')) {
        content_type = 'cta_suscribirme';
        content_interaction = 'newsletter';
    }

    if (clickedElement && clickedElement.closest('.tabs-posts__nav')) {
        content_type = 'tab_blog';
        content_interaction = clickedElement.textContent.trim();
    }

    if (clickedElement && clickedElement.closest('.table-entidades')) {
        content_type = 'text_sitio-web';
        content_interaction = clickedElement.href;
    }
    if (clickedElement && clickedElement.closest('#content-entidades')) {
        content_type = 'cta_bancos';
        content_interaction = clickedElement.querySelector('.inner-logo').getAttribute('alt');
    }

    if (clickedElement && clickedElement.closest('.content-comercios')) {
        content_type = 'cta_comercios';
        content_interaction = clickedElement.querySelector('.inner-logo').getAttribute('alt');
    }

    if (clickedElement.classList.contains('icon')) {
        content_type = 'cta_redes-sociales';
        content_interaction = clickedElement.classList[1].replace('icon-', '');
    }

    if (content_type !== null && content_interaction !== null) {
        dataLayer.push({
            'event': 'select_content',
            content_type,
            content_interaction
        });
    }
});

document.addEventListener("change", (event) => {
    if (event.target.id === 'language-select') {
        dataLayer.push({
            'event': 'select_content',
            'content_type': 'menu_footer',
            'content_interaction': event.target.selectedOptions[0].textContent.trim()
        });
    }
});

